import xml.etree.ElementTree as ET
import base64
import re

def extract_data_from_xml(xml_data: str):
    try:
        root = ET.fromstring(xml_data)
    except ET.ParseError as e:
        print(f"XML Parsing error: {e}")
        return None
    cono = ""    
    for elem in root.iter():
        if 'FilePath' in elem.attrib:
            filePath = elem.attrib['FilePath']
            last_part = filePath.split('/')[-1]
            interfaceName=filePath.split('/')[-2]
            if last_part.isdigit() and len(last_part) == 3:
                cono = last_part
            else:
                print("Invalid code:", last_part)
            break

    extracted_data = ""
    raw_data = root.find(".//RawData")
    if raw_data is not None:
        try:
            decoded_data = base64.b64decode(raw_data.text.strip())
            decoded_data_str = decoded_data.decode('windows-1255', errors='ignore')
            extracted_data+= cono+";"+interfaceName + '\r\n' + decoded_data_str
        except Exception as e:
            print(f"RawData Decoding error: {e}")
    if not extracted_data:
        print("No data found in XML.")
        return None
    return extracted_data

